  1→import { useEffect, useRef, useState } from "react"
  2→import { useAuth } from "../../Context/useAuth";
  3→import { MoonLoader } from "react-spinners";
  4→import { addReply, getPostReplies } from "../../../API/Api";
  5→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  6→import { handleClickProfile } from "../../../helpers/handleClicks";
  7→import { useNavigate } from "react-router-dom";
  8→import { motion, AnimatePresence } from "framer-motion";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→
 12→const incrementReplyCount = (old, parentId) => {
 13→    if (!old || !Array.isArray(old.pages)) return old;
 14→
 15→    return {
 16→        ...old,
 17→        pages: old.pages.map((page) => ({
 18→            ...page,
 19→            comments: Array.isArray(page?.comments)
 20→                ? page.comments.map((comment) => {
 21→                    if (comment?.id !== parentId) return comment;
 22→                    return {
 23→                        ...comment,
 24→                        reply_count: (comment?.reply_count || 0) + 1,
 25→                    };
 26→                })
 27→                : page?.comments,
 28→        })),
 29→    };
 30→};
 31→
 32→
 33→const CommentsCards = ({comments, postId}) =>{
 34→    const {user, session} = useAuth();
 35→    const userId = user?.userData[0].id;
 36→    const queryClient = useQueryClient();
 37→
 38→    const [showReplyInput, setShowReplyInput] = useState(false);
 39→    const [showReplies, setShowReplies] = useState(false);
 40→
 41→    const [reply, setReply] = useState('')
 42→    const [replyLoaderId, setReplyLoaderId] = useState('');
 43→
 44→    const navigate = useNavigate();
 45→    const replyInputRef = useRef(null);
 46→
 47→    const clickProfile = handleClickProfile(navigate);
 48→
 49→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 50→        queryKey: ['getPostReplies', comments.id],
 51→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 52→        getNextPageParam: (lastPage) => {
 53→            if(lastPage.hasMore){
 54→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 55→                return lastReply.id;
 56→            } else{
 57→                return undefined
 58→            }
 59→        },
 60→        refetchOnWindowFocus: false,
 61→        enabled: showReplies
 62→    })
 63→
 64→    const handleClickReplyButton = (e) =>{
 65→        e.stopPropagation();
 66→        setShowReplyInput(!showReplyInput);
 67→    }
 68→
 69→    const handleShowMoreReplies = () => {
 70→        if(!isFetchinNextPage){
 71→            fetchNextPage();
 72→        }
 73→    }
 74→
 75→    const submitReply = async(parent_id, receiver_id) => {
 76→        const trimmedReply = reply.trim();
 77→        if (!trimmedReply) return;
 78→
 79→        setReplyLoaderId(parent_id)
 80→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 81→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 82→
 83→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 84→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 85→
 86→        const optimisticReply = {
 87→            id: `optimistic-reply-${Date.now()}`,
 88→            post_id: postId,
 89→            parent_id: parent_id,
 90→            comment: trimmedReply,
 91→            created_at: new Date().toISOString(),
 92→            user_id: user?.userData?.[0]?.id,
 93→            users: {
 94→                id: user?.userData?.[0]?.id,
 95→                name: user?.userData?.[0]?.name,
 96→                image_url: user?.userData?.[0]?.image_url,
 97→                badge: user?.userData?.[0]?.badge,
 98→            },
 99→            reply_count: 0,
100→        };
101→
102→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
103→            if (!old || !Array.isArray(old.pages)) {
104→                return {
105→                    pageParams: [null],
106→                    pages: [{ data: [optimisticReply], hasMore: false }],
107→                };
108→            }
109→
110→            return {
111→                ...old,
112→                pages: old.pages.map((page, index) =>
113→                    index === 0
114→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
115→                        : page
116→                ),
117→            };
118→        });
119→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
120→
121→        try {
122→            const formdata = new FormData();
123→            formdata.append('reply', trimmedReply);
124→
125→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
126→            if(message){
127→                console.log(message);
128→            }
129→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
130→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
131→            setReply('')
132→            setShowReplies(true)
133→        } catch (error) {
134→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
135→            queryClient.setQueryData(['postComments', postId], previousComments);
136→            setReply('')
137→            throw new Error('error adding replies')
138→        } finally {
139→            setReplyLoaderId('')
140→            setShowReplyInput(false);
141→        }
142→    }
143→
144→    useEffect(() =>{
145→        if(showReplyInput && replyInputRef.current){
146→            const timer = setTimeout(() => {
147→                replyInputRef.current.focus();
148→                replyInputRef.current.scrollIntoView({behavior: 'smooth', block: 'center'})
149→            }, 50);
150→
151→            return () => {
152→                clearTimeout(timer)
153→            }
154→        }
155→    }, [showReplyInput])
156→
157→    const replies = data?.pages.flatMap((page) => page.data) || [];
158→
159→    return(
160→        <div style={{marginLeft: comments?.parent_id ? 20 : 0}} className="cm-card">
161→            {comments?.parent_id && <div className="cm-thread-line" />}
162→
163→            <div className="cm-card-content">
164→                <div className="cm-user-row">
165→                    <div
166→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
167→                        className={`cm-avatar-container ${comments?.users?.badge === 'legend' ? 'cm-ring-legend' : comments?.users?.badge === 'og' ? 'cm-ring-og' : ''}`}
168→                    >
169→                        <img className="cm-avatar" src={comments?.users?.image_url || '/assets/profile.jpg'} alt={`${comments?.users?.name || "User"} profile picture`} />
170→                    </div>
171→                    <span
172→                        onClick={(e) => clickProfile(e, user?.userData[0].id, comments?.user_id)}
173→                        className="cm-username"
174→                    >
175→                        {comments?.users?.name}
176→                    </span>
177→                    <VerifiedBadge badge={comments?.users?.badge} size={14} />
178→                    <span className="cm-dot">&middot;</span>
179→                    <span className="cm-date">{formatPostDate(comments?.created_at)}</span>
180→                </div>
181→
182→                <p className="cm-body">{comments?.comment}</p>
183→
184→                <div className="cm-card-actions">
185→                    <button onClick={(e) => handleClickReplyButton(e)} className="cm-reply-btn">
186→                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
187→                            <polyline points="9 17 4 12 9 7" />
188→                            <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
189→                        </svg>
190→                        Reply
191→                    </button>
192→
193→                    {comments?.reply_count > 0 && (
194→                        <button onClick={() => setShowReplies(!showReplies)} className="cm-toggle-replies-btn">
195→                            <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
196→                                <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
197→                            </svg>
198→                            {showReplies ? 'Hide' : 'Show'} {comments?.reply_count} {comments?.reply_count === 1 ? 'reply' : 'replies'}
199→                        </button>
200→                    )}
201→                </div>
202→
203→                {replyLoaderId === comments.id && (
204→                    <div className="cm-reply-loading">
205→                        <MoonLoader size={16} color="var(--loader-color)" speedMultiplier={0.8}/>
206→                    </div>
207→                )}
208→
209→                <AnimatePresence>
210→                    {showReplyInput && (
211→                        <motion.div
212→                            initial={{ height: 0, opacity: 0 }}
213→                            animate={{ height: "auto", opacity: 1 }}
214→                            exit={{ height: 0, opacity: 0 }}
215→                            transition={{ duration: 0.2 }}
216→                            className="cm-reply-input-wrapper"
217→                        >
218→                            <textarea
219→                                ref={replyInputRef}
220→                                maxLength={200}
221→                                value={reply}
222→                                onChange={(e) => setReply(e.target.value)}
223→                                className="cm-reply-textarea"
224→                                placeholder={`Replying to ${comments?.users?.name}...`}
225→                                rows={1}
226→                            />
227→                            <div className="cm-reply-action-row">
228→                                <span className={`cm-reply-char-count ${reply.length > 199 ? 'cm-char-limit' : ''}`}>
229→                                    {reply.length}/200
230→                                </span>
231→                                <button
232→                                    onClick={() => submitReply(comments?.id, comments?.users?.id)}
233→                                    className="cm-reply-submit-btn"
234→                                    disabled={!reply.trim()}
235→                                >
236→                                    Submit
237→                                </button>
238→                            </div>
239→                        </motion.div>
240→                    )}
241→                </AnimatePresence>
242→
243→                <AnimatePresence>
244→                    {showReplies && (
245→                        <motion.div
246→                            initial={{ opacity: 0 }}
247→                            animate={{ opacity: 1 }}
248→                            exit={{ opacity: 0 }}
249→                            transition={{ duration: 0.2 }}
250→                            className="cm-replies-thread"
251→                        >
252→                            {replies?.map((r) => (
253→                                <CommentsCards postId={postId} key={r.id} comments={r}/>
254→                            ))}
255→
256→                            {hasNextPage && (
257→                                <button onClick={handleShowMoreReplies} className="cm-show-more-replies">
258→                                    {isFetchinNextPage ? 'Loading...' : 'Show more replies'}
259→                                </button>
260→                            )}
261→                        </motion.div>
262→                    )}
263→                </AnimatePresence>
264→            </div>
265→        </div>
266→    )
267→}
268→
269→export default CommentsCards;
