 89→export const addCommentService = async(userId, comments, postId, receiverId) => {
 90→    if(!comments || !postId || !receiverId){
 91→        console.error('comments || postId || receiverId is undefined');
 92→        throw {status: 400, error: 'comments || postId || receiverId is undefined'};
 93→    }
 94→
 95→    if(!userId){
 96→        console.error('userId is undefined')
 97→        throw {status: 400, error: 'userId is undefined'};
 98→    }
 99→    const isOwnContent = userId === receiverId;
100→
101→    const insertNotifPromise = supabase
102→    .from('notifications')
103→    .insert(
104→        {
105→            sender_id: userId,
106→            receiver_id: receiverId,
107→            journal_id: postId,
108→            read: false,
109→            type: 'comment'
110→        }
111→    )
112→
113→    const insertCommentPromise = supabase
114→    .from('comments')
115→    .insert(
116→        {
117→            comment: comments,
