151→export const useLikeMutation = (session, userId) =>{
152→    const queryClient = useQueryClient();
153→    const inFlightLikeIdsRef = useRef(new Set());
154→
155→    const mutation = useMutation({
156→        mutationFn: (data) => clickLike(session?.access_token, data), //receiving the object data {journalId: the Id}
157→
158→        onMutate: async(data) => {
159→            queryClient.cancelQueries({ queryKey: ['journals'] });
160→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
161→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
162→
163→            const previousData = [
164→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
165→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
166→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
167→            ];
168→
169→            const updater = (journal) => {
170→                if(journal.id !== data.journalId) return journal;
171→
172→                const isLiked = normalizeInteractionFlag(journal?.has_liked);
173→                const count = normalizeCount(journal?.like_count?.[0]?.count);
174→                const nextCount = getNextToggleCount(isLiked, count);
175→
176→                return{
177→                    ...journal,
178→                    has_liked: !isLiked,
179→                    like_count: [{count: nextCount}]
180→                };
181→            };
182→
183→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
184→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
185→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
186→
187→        return {previousData};
188→    },
189→    onError: (err, data, context) => {
190→      context?.previousData?.forEach(([key, value]) => {
191→          queryClient.setQueryData(key, value);
192→      });
193→    },
194→    onSettled: () => {
195→      queryClient.invalidateQueries({ queryKey: ['journals'] });
196→      queryClient.invalidateQueries({ queryKey: ['userJournals'] });
197→      queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
198→    },
199→});
200→
201→    const guardedMutate = (variables, options) => {
202→        const journalKey = toJournalKey(variables?.journalId);
203→        if(journalKey && inFlightLikeIdsRef.current.has(journalKey)){
204→            return;
205→        }
206→
207→        if(journalKey){
208→            inFlightLikeIdsRef.current.add(journalKey);
209→        }
210→
211→        mutation.mutate(variables, {
212→            ...options,
213→            onSettled: (data, error, vars, context) => {
214→                if(journalKey){
215→                    inFlightLikeIdsRef.current.delete(journalKey);
216→                }
217→                options?.onSettled?.(data, error, vars, context);
218→            }
219→        });
220→    };
221→
222→    const guardedMutateAsync = async (variables, options) => {
223→        const journalKey = toJournalKey(variables?.journalId);
224→        if(journalKey && inFlightLikeIdsRef.current.has(journalKey)){
225→            return {message: 'skipped'};
226→        }
227→
228→        if(journalKey){
229→            inFlightLikeIdsRef.current.add(journalKey);
230→        }
231→
232→        try {
233→            return await mutation.mutateAsync(variables, options);
234→        } finally {
235→            if(journalKey){
236→                inFlightLikeIdsRef.current.delete(journalKey);
237→            }
238→        }
239→    };
240→
241→    return {
242→        ...mutation,
243→        mutate: guardedMutate,
244→        mutateAsync: guardedMutateAsync
245→    };
246→}
